structTreeNode*deleteNode(structTreeNode*root,intkey){
if(root==NULL)returnroot;
if(key<root->data){
root->left=deleteNode(root->left,key);
}elseif(key>root->data){
root->right=deleteNode(root->right,key);
}else{
// FOUND the node to delete — now handle 3 cases:
if(root->left==NULL){// Case 1: no left child (0 or 1 children)
structTreeNode*temp=root->right;
free(root);
returntemp;
}elseif(root->right==NULL){// Case 2: no right child
structTreeNode*temp=root->left;
free(root);
returntemp;
}
// Case 3: two children — replace with the inorder successor
// (the smallest value in the right subtree), then delete that successor
structTreeNode*successor=findMin(root->right);
root->data=successor->data;
root->right=deleteNode(root->right,successor->data);
}
returnroot;
}
Why the inorder successor? Replacing the deleted node’s value with the smallest value from its right subtree
preserves the BST property automatically — everything in the left subtree is still smaller, and everything
remaining in the right subtree is still larger.
