}
intgetBalance(structAVLNode*n){
return(n==NULL)?0:height(n->left)-height(n->right);
}
structAVLNode*rightRotate(structAVLNode*y){
structAVLNode*x=y->left;
structAVLNode*T2=x->right;
x->right=y;// perform rotation
y->left=T2;
y->height=maxInt(height(y->left),height(y->right))+1;// update heights, y first
x->height=maxInt(height(x->left),height(x->right))+1;
returnx;// x is the new subtree root
}
structAVLNode*leftRotate(structAVLNode*x){
structAVLNode*y=x->right;
structAVLNode*T2=y->left;
y->left=x;
