y->height=maxInt(height(y->left),height(y->right))+1;
returny;
}
structAVLNode*insertAVL(structAVLNode*node,intkey){
if(node==NULL){
structAVLNode*newNode=(structAVLNode*)malloc(sizeof(structAVLNode));
newNode->key=key;
newNode->left=newNode->right=NULL;
newNode->height=1;
returnnewNode;
