if(key<node->key)
node->left=insertAVL(node->left,key);
elseif(key>node->key)
node->right=insertAVL(node->right,key);
else
returnnode;// no duplicate keys
node->height=1+maxInt(height(node->left),height(node->right));
intbalance=getBalance(node);
if(balance>1&&key<node->left->key)// LL
returnrightRotate(node);
if(balance<-1&&key>node->right->key)// RR
returnleftRotate(node);
if(balance>1&&key>node->left->key){// LR
node->left=leftRotate(node->left);
returnrightRotate(node);
}
if(balance<-1&&key<node->right->key){// RL
node->right=rightRotate(node->right);
returnleftRotate(node);
}
returnnode;// already balanced
}
You won’t often be asked to code a full AVL insert from scratch in an interview (it’s a lot to get right under
time pressure), but you’re very likely to be askedwhythey exist, what a rotation does conceptually, and to
trace through what happens to a small tree — so understanding thewhymatters more than memorizing every
rotation case.
