swap(&arr[i],&arr[(i-1)/2]);
i=(i-1)/2;
}
}
intextractMin(intarr[],int*n){
introot=arr[0];
arr[0]=arr[*n-1];// move last element to root
(*n)--;
minHeapify(arr,*n,0);// restore heap property
returnroot;
}
