if(low>high)return-1;
intmid=low+(high-low)/2;
if(arr[mid]==target)returnmid;
if(arr[mid]<target)returnbinarySearchRecursive(arr,mid+1,high,target);
returnbinarySearchRecursive(arr,low,mid-1,target);
}
